#include <bits/stdc++.h>
using namespace std;

const int MOD = 1e9 + 7;

int countWays(int n) {
    vector<long long> dp(n + 1, 0);
    dp[0] = 1;
    dp[1] = 1;

    for (int i = 2; i <= n; ++i) {
        dp[i] = (dp[i - 1] + (i - 1) * dp[i - 2]) % MOD;
    }
    return dp[n];
}

int main() {
    int t;
    cin >> t;

    while (t--) {
        int n;
        cin >> n;
        cout << countWays(n) << endl;
    }

    return 0;
}
